INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "キャル", 7001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "たまには\n協力するのもいいんじゃない？\nあたしも手を貸してあげる", 1, -363.0, 0, "2015/12/17 15:00:00", 106001, 7);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "コッコロ", 7002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "多くの方と協力して\n戦えるようです\n主さまなら、さぞ\nご活躍なさることでしょう", 1, -363.0, 0, "2015/12/17 15:00:00", 105901, 7);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "ペコリーヌ", 7003, 1, "2030/12/17 14:59:59", 0.0, 0.0, "たくさんの人と一緒に\n協力バトルです！\nがんばりましょう☆", 1, -363.0, 0, "2015/12/17 15:00:00", 105801, 7);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "ペコリーヌ", 10001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ジュエルを食べ物…\nいえ、貴重品と交換できます！", 1, -363.0, 0, "2015/12/17 15:00:00", 105801, 10);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "キャル", 10002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ジュエルはよく考えて\n使うことね\n無駄遣い厳禁！", 1, -363.0, 0, "2015/12/17 15:00:00", 106001, 10);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "コッコロ", 10003, 1, "2030/12/17 14:59:59", 0.0, 0.0, "主さまのジュエルで\n貴重な品々を購入できます\nですが、無駄遣いは\n『めっ』でございますよ", 1, -363.0, 0, "2015/12/17 15:00:00", 105901, 10);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "シェフィ", 10004, 2, "2030/12/17 14:59:59", 0.0, 0.0, "ジュエルがあれば\n貴重品と交換できるみたい\n大事に使いましょうね", 1, -363.0, 2104010, "2015/12/17 15:00:00", 106401, 10);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "ペコリーヌ", 12001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "特定の条件を達成すると\n報酬がもらえますよ！\nがんばりましょう♪　", 1, -416.5, 0, "2015/12/17 15:00:00", 105801, 12);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "キャル", 13001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "思い出が詰まってるって\nいろいろあったけど\n振り返るのもいいんじゃない？", 1, -363.0, 0, "2015/12/17 15:00:00", 106001, 13);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "コッコロ", 13002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "主さまとの楽しい日々…\nこちらで何度でも\n思い返しましょう♪", 1, -363.0, 0, "2015/12/17 15:00:00", 105901, 13);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "シェフィ", 13003, 2, "2030/12/17 14:59:59", 0.0, 0.0, "みんなとの大切な思い出が\nたくさん詰まってるのね\n一緒に振り返って、\n心に刻みたいわ", 1, -363.0, 2104010, "2015/12/17 15:00:00", 106401, 13);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "ペコリーヌ", 13004, 1, "2030/12/17 14:59:59", 0.0, 0.0, "女の子との思い出が\nたくさん見られますよ！\nヒューヒュー♪\nモテモテですねー☆", 1, -363.0, 0, "2015/12/17 15:00:00", 105801, 13);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "コッコロ", 14001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "育成に必要なアイテムが\n獲得できるクエストです\nわたくし、主さまのために、\n強くなりますよ", 1, -363.0, 0, "2015/12/17 15:00:00", 105901, 14);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "シェフィ", 14002, 2, "2030/12/17 14:59:59", 0.0, 0.0, "このクエストを攻略すると、\nアイテムが手に入るらしいわ。\nもっと強くなるために、\n一生懸命がんばるわね！", 1, -363.0, 2104010, "2015/12/17 15:00:00", 106401, 14);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "ペコリーヌ", 14003, 1, "2030/12/17 14:59:59", 0.0, 0.0, "このクエストを攻略すれば、\nアイテムがもらえますよ\nたくさん集めて、どんどん\n強くなっちゃいましょう！", 1, -363.0, 0, "2015/12/17 15:00:00", 105801, 14);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "キャル", 14004, 1, "2030/12/17 14:59:59", 0.0, 0.0, "クエストを攻略すると、\nアイテムが手に入るんだって\nもらえるものは、\nもらっておきましょ！", 1, -363.0, 0, "2015/12/17 15:00:00", 106001, 14);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "コッコロ", 15001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "主さま、旅の準備を整えて\nより充実した冒険をいたし\nましょう", 1, -470.0, 0, "2015/12/17 15:00:00", 105901, 15);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "シェフィ", 16001, 2, "2030/12/17 14:59:59", 0.0, 0.0, "ねぇ…クランに加入してみない？\n一人も楽しいけど、みんなと\n一緒も賑やかでいいと思うの", 1, -363.0, 2104010, "2015/12/17 15:00:00", 106401, 16);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "ペコリーヌ", 16002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "クランに加入してみませんか？\nみんなといっしょに冒険した方が、\n楽しいですよ！", 1, -363.0, 0, "2015/12/17 15:00:00", 105801, 16);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "キャル", 16003, 1, "2030/12/17 14:59:59", 0.0, 0.0, "クランに入れるらしいわよ\nせっかくだから入ってみたら？\nけっこう楽しいみたいよ♪", 1, -363.0, 0, "2015/12/17 15:00:00", 106001, 16);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "コッコロ", 16004, 1, "2030/12/17 14:59:59", 0.0, 0.0, "こちらでクランに加入できます\n素敵なクランがたくさんあって、\n目移りしてしまいますね", 1, -363.0, 0, "2015/12/17 15:00:00", 105901, 16);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "コッコロ", 17002, 1, "2030/12/17 14:59:59", 0.0, 0.0, " こちらではクランバトルに\n 参加された仲間のみなさんの\n 活躍を振り返ることができます", 1, -363.0, 0, "2015/12/17 15:00:00", 105901, 17);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "キャル", 17004, 1, "2030/12/17 14:59:59", 0.0, 0.0, "模擬戦の戦績もアンタが\n気に入ったものがあれば\n記録しておけるのね", 1, -363.0, 0, "2015/12/17 15:00:00", 106001, 25);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "コッコロ", 17005, 1, "2030/12/17 14:59:59", 0.0, 0.0, "主さま、今回のクランバトルでの\nご活躍が記録されています\nバトルの参考にいたしましょう", 1, -363.0, 0, "2015/12/17 15:00:00", 105901, 25);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "シェフィ", 17006, 2, "2030/12/17 14:59:59", 0.0, 0.0, "今回のクランバトルの調子は\nどうかしら？\n戦績を見れば、次のバトルに\n活かせるかもしれないわ", 1, -363.0, 2104010, "2015/12/17 15:00:00", 106401, 25);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "ペコリーヌ", 17007, 1, "2030/12/17 14:59:59", 0.0, 0.0, "今回のクランバトルでの戦績を\nおさらいできますよ！\n私にも見せてください☆", 1, -363.0, 0, "2015/12/17 15:00:00", 105801, 25);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "カリン", 18001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ようこそ！\nこちらでは、\nギルドハウスで流れる音楽の\n変更や購入が出来ますよ", 1, -363.0, 0, "2015/12/17 15:00:00", 190801, 18);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 2, "カリン", 18002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ＢＧＭの変更や購入は、こちらから\nできますよ\n素敵な音楽を、たくさんご用意\nいたしました！", 1, -363.0, 0, "2015/12/17 15:00:00", 190801, 18);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 3, "カリン", 19001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ギルドハウスの\nＢＧＭを変更できますよ\nあなたの好きな曲、\n私にも聴かせてくださいね", 1, -470.0, 0, "2015/12/17 15:00:00", 190801, 19);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 4, "カリン", 19002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "こちらでは、ＢＧＭの変更が\nできますよ\nどんな曲に変更しますか？\nふふふ、私も楽しみです♪", 1, -470.0, 0, "2015/12/17 15:00:00", 190801, 19);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 5, "カリン", 20001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "こちらでは、ＢＧＭを購入\nすることができますよ\n試聴することもできるので、\nじっくり選んでくださいね", 1, -470.0, 0, "2015/12/17 15:00:00", 190801, 20);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 6, "カリン", 20002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "いらっしゃいませ！\nＢＧＭの購入はこちらです\n素敵な曲がたくさんあって、\n目移りしちゃいますね", 1, -470.0, 0, "2015/12/17 15:00:00", 190801, 20);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "キャル", 21001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ここで手に入れたアイテムで\n専用装備を作成できるみたいね\nアイテムが集まったら\nさっそく作ってみましょ！", 1, -363.0, 0, "2015/12/17 15:00:00", 106001, 21);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "コッコロ", 21002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "攻略すると珍しいアイテムが\n手に入りますよ\nこのアイテムで専用装備を\n作成できるようです", 1, -363.0, 0, "2015/12/17 15:00:00", 105901, 21);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "シェフィ", 21003, 2, "2030/12/17 14:59:59", 0.0, 0.0, "専用装備が欲しいなら\nこのクエストに挑戦するといいわ\n集めた素材でもっともっと\n強くなりましょう", 1, -363.0, 2104010, "2015/12/17 15:00:00", 106401, 21);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "ペコリーヌ", 21004, 1, "2030/12/17 14:59:59", 0.0, 0.0, "専用装備の作成に必要な\nアイテムを獲得できますよ\nたくさん集めてどんどん\n強くなりましょう！", 1, -363.0, 0, "2015/12/17 15:00:00", 105801, 21);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "カリン", 22001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "投票はこちらです\nあなたが応援したい女の子に\n思いを込めた一票を\nお願いします！", 1, -430.0, 0, "2015/12/17 15:00:00", 190801, 22);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 2, "カリン", 22002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ようこそ！\nあなたが思いを寄せるのは\nどの女の子ですか？\n応援してあげてくださいね！", 1, -430.0, 0, "2015/12/17 15:00:00", 190801, 22);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 3, "カリン", 23001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "たくさんの投票、\nありがとうございました\n結果発表を楽しみに\n待っていてくださいね！", 1, -430.0, 0, "2015/12/17 15:00:00", 190801, 23);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 4, "カリン", 23002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ただ今、人気投票の\n集計中です\n結果が出るまでもう少しだけ\nお待ちくださいね", 1, -430.0, 0, "2015/12/17 15:00:00", 190801, 23);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 1, "エリコ（バレンタイン）", 24001, 1, "2030/12/17 14:59:59", 8.0, 4.08, "あなた様が手伝ってくださった\nチョコレートケーキ\n美味しくないはずがありませんわ", 2, -385.0, 0, "2019/01/31 12:00:00", 109001, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 2, "エリコ（バレンタイン）", 24002, 1, "2030/12/17 14:59:59", 8.0, 5.0, "このような失敗、あなた様が\nするはずありません\nもう一度挑戦してみましょう", 2, -385.0, 0, "2019/01/31 12:00:00", 109001, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 3, "エリコ（バレンタイン）", 24003, 1, "2030/12/17 14:59:59", 8.0, 10.11, "あなた様のために\n作っているケーキを\nあなた様に手伝っていただく……\nことになるなんて……クスクス", 2, -385.0, 0, "2019/01/31 12:00:00", 109001, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 4, "エリコ（バレンタイン）", 24004, 1, "2030/12/17 14:59:59", 8.0, 4.0, "あまり気に病む必要はありませんわ\nこれからは私がたっぷりと\n時間をかけて教えて差し上げますから", 2, -385.0, 0, "2019/01/31 12:00:00", 109001, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 5, "エリコ（バレンタイン）", 24005, 1, "2030/12/17 14:59:59", 8.0, 6.0, "今回は調子が悪かった……のですか？\nあなた様が手伝ってくれたものなら\nわたしはどんなものでも……クスクス", 2, -385.0, 0, "2019/01/31 12:00:00", 109001, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 6, "エリコ（バレンタイン）", 24006, 1, "2030/12/17 14:59:59", 0.0, 0.0, "あなた様が手がけた\nチョコレートケーキは\n私にとっての宝物……\n侮辱する者は生かしておきませんわ", 1, 0.0, 0, "2019/01/31 12:00:00", 109002, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 7, "エリコ（バレンタイン）", 24007, 1, "2030/12/17 14:59:59", 0.0, 0.0, "とても素晴らしい出来栄えですわ！\nあなた様にふさわしい\nチョコレートケーキができました", 1, 0.0, 0, "2019/01/31 12:00:00", 109002, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 8, "エリコ（バレンタイン）", 24008, 1, "2030/12/17 14:59:59", 0.0, 0.0, "私を手伝ってくれたあなた様は\nすでに私の虜……\n甘い世界に誘って差し上げますわ", 1, 0.0, 0, "2019/01/31 12:00:00", 109002, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 9, "エリコ（バレンタイン）", 24009, 1, "2030/12/17 14:59:59", 0.0, 0.0, "あなた様の愛情\nしかと受け止めました\nこれが……私たちの初めての\n共同作業ですわね……クスクス", 1, 0.0, 0, "2019/01/31 12:00:00", 109002, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 10, "エリコ（バレンタイン）", 24010, 1, "2030/12/17 14:59:59", 0.0, 0.0, "これは世界一の\nチョコレートケーキですわ\nだって、あなた様が腕によりをかけて\n作ってくださったんですもの", 1, 0.0, 0, "2019/01/31 12:00:00", 109002, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 1, "シズル（バレンタイン）", 24011, 1, "2030/12/17 14:59:59", 8.0, 2.12, "上手にできなくて残念だった？\nでも、弟くんの気持ちが嬉しいな\nいつだってお姉ちゃんは\nそばにいるからね♪", 2, -385.0, 0, "2019/01/31 12:00:00", 109101, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 2, "シズル（バレンタイン）", 24012, 5, "2030/12/17 14:59:59", 8.0, 4.19, "うーん、弟くんには珍しく\n緊張しちゃったのかな？\nもう一度チャレンジしてみる？", 2, -385.0, 0, "2019/01/31 12:00:00", 109101, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 3, "シズル（バレンタイン）", 24013, 2, "2030/12/17 14:59:59", 8.0, 2.3, "お姉ちゃんのお手伝い、\nよくできました！\nあー、\nまだつまみ食いしちゃダメだぞ！", 4, -385.0, 0, "2019/01/31 12:00:00", 109101, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 4, "シズル（バレンタイン）", 24014, 1, "2030/12/17 14:59:59", 0.0, 0.0, "見てみて！\nスポンジに綺麗な焼き目がついてるよ\nさっすが弟くんだね！", 1, 0.0, 0, "2019/01/31 12:00:00", 109102, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 5, "シズル（バレンタイン）", 24015, 5, "2030/12/17 14:59:59", 8.0, 5.23, "まぁまぁ、落ち込まないで\n見た目は……個性的だけど、\n味は絶対美味しいはずだから！", 2, -385.0, 0, "2019/01/31 12:00:00", 109101, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 6, "シズル（バレンタイン）", 24016, 1, "2030/12/17 14:59:59", 0.0, 0.0, "弟くんみたいな\n可愛いケーキができたよ！\n早く食べてみたいでしょ♪", 1, 0.0, 0, "2019/01/31 12:00:00", 109102, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 7, "シズル（バレンタイン）", 24017, 1, "2030/12/17 14:59:59", 8.0, 5.01, "あれれ？　弟くん、指に\nチョコレートがくっついてるよ？\nお姉ちゃんが舐めてあげるね、\nはぁむ！", 2, -385.0, 0, "2019/01/31 12:00:00", 109101, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 8, "シズル（バレンタイン）", 24018, 1, "2030/12/17 14:59:59", 0.0, 0.0, "なかなか上手にできたんじゃない？\nでも弟くんはまだまだできる子！\nお姉ちゃん、信じてるからね", 1, 0.0, 0, "2019/01/31 12:00:00", 109102, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 9, "シズル（バレンタイン）", 24019, 1, "2030/12/17 14:59:59", 0.0, 0.0, "わぁ～、\nとっても美味しそうにできたね！\n弟くん手慣れてたから\nお姉ちゃん安心して任せられちゃった！", 1, 0.0, 0, "2019/01/31 12:00:00", 109102, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10011, 10, "シズル（バレンタイン）", 24020, 1, "2030/12/17 14:59:59", 0.0, 0.0, "や～ん、弟くんが手伝ってくれた\nチョコレートケーキ！\nすっごく美味しそうにできたね♪", 1, 0.0, 0, "2019/01/31 12:00:00", 109102, 24);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "シェフィ", 26001, 2, "2030/12/17 14:59:59", 0.0, 0.0, "ここから先は神聖な場所みたい\nどんなお宝が眠っているのか、\n今から探索するのが楽しみね♪", 1, -363.0, 2104010, "2015/12/17 15:00:00", 106401, 26);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "ペコリーヌ", 26002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ここから先は神聖な場所\nみたいです！\nどんなお宝が手に入るか\n楽しみですね！", 1, -363.0, 0, "2015/12/17 15:00:00", 105801, 26);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "キャル", 26003, 1, "2030/12/17 14:59:59", 0.0, 0.0, "この先は神聖な場所みたい。\n手に入るお宝も並じゃないけど\n気を付けていかないと\n痛い目にあうわよ", 1, -363.0, 0, "2015/12/17 15:00:00", 106001, 26);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "コッコロ", 26004, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ここから先は神聖な場所\nでございます。\n気を引き締めてお宝の\n調査探索に参りましょう", 1, -363.0, 0, "2015/12/17 15:00:00", 105901, 26);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "シェフィ", 27001, 2, "2030/12/17 14:59:59", 0.0, 0.0, "ここにさらなる力を得るための\nアイテムが眠っている…って\nみんな言ってるわ。ふふっ、\nそれじゃあ挑戦してみましょうか", 1, -363.0, 2104010, "2015/12/17 15:00:00", 106401, 27);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "ペコリーヌ", 27002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ここにさらなる力を得るための\nアイテムが眠っているみたい\nです！　どこから挑戦するか\n迷っちゃいますね！", 1, -363.0, 0, "2015/12/17 15:00:00", 105801, 27);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "キャル", 27003, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ここにさらなる力を得るための\nアイテムが眠っているみたい！\nどんどん挑戦して\n強くなっちゃいましょ！", 1, -363.0, 0, "2015/12/17 15:00:00", 106001, 27);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "コッコロ", 27004, 1, "2030/12/17 14:59:59", 0.0, 0.0, "こちらにさらなる力を得る\nためのアイテムが眠っている\nようです。主さま、どこから\n挑戦いたしましょう。", 1, -363.0, 0, "2015/12/17 15:00:00", 105901, 27);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "カリン", 28001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ようこそ！\n皆さんの素敵な出会いを\nギルド管理協会が\nお手伝いします！", 1, -363.0, 0, "2019/09/24 15:00:00", 190801, 28);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 2, "カリン", 28002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ギルド管理協会です\nフレンドに関しては\nこちらでご確認ください", 1, -363.0, 0, "2019/09/24 15:00:00", 190801, 28);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 3, "カリン", 29001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "こちらがフレンドの\n皆さんです\n素敵な関係を\n築いてくださいね！", 1, -409.0, 0, "2019/09/24 15:00:00", 190801, 29);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 4, "カリン", 29002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "こちらの一覧で\nフレンドのプロフィールを\n確認できますよ", 1, -409.0, 0, "2019/09/24 15:00:00", 190801, 29);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 5, "カリン", 30001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "フレンド管理は\nこちらになります\n新しいフレンドとの出会いを\n楽しんでくださいね！", 1, -409.0, 0, "2019/09/24 15:00:00", 190801, 30);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 6, "カリン", 30002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "フレンドの申請や\n承認ができますよ\nどうぞ、良き交流を！", 1, -409.0, 0, "2019/09/24 15:00:00", 190801, 30);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 7, "カリン", 31001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "バトルをして力比べを\nしてみましょう！\n実力が試されますね、\n頑張ってください！", 1, -409.0, 0, "2019/10/31 12:00:00", 190801, 31);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 8, "カリン", 31002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "気になるパーティと\nバトルをしてみましょう！\nどちらが勝利するのか、\n私も楽しみにしていますね", 1, -409.0, 0, "2019/10/31 12:00:00", 190801, 31);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "カリン", 32001, 1, "2020/01/04 4:59:59", 0.0, 0.0, "ルーキーの皆さんのために\n特別なミッションを\nご用意いたしました！\nぜひ、挑戦してください！", 1, -409.0, 0, "2019/12/20 5:00:00", 190801, 32);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 2, "カリン", 32002, 1, "2020/01/04 4:59:59", 0.0, 0.0, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", 1, -409.0, 0, "2019/12/20 5:00:00", 190801, 32);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 3, "カリン", 33001, 1, "2020/01/04 4:59:59", 0.0, 0.0, "フレンドになって\n初心者の方を応援しましょう！\n素敵な報酬が待っていますよ！", 1, -409.0, 0, "2019/12/20 5:00:00", 190801, 33);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 4, "カリン", 33002, 1, "2020/01/04 4:59:59", 0.0, 0.0, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", 1, -409.0, 0, "2019/12/20 5:00:00", 190801, 33);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 5, "カリン", 34001, 1, "2020/01/10 11:59:59", 0.0, 0.0, "お疲れ様でした！\nミッションの報酬の受け取りは\nこちらからできますよ！", 1, -409.0, 0, "2020/01/04 5:00:00", 190801, 34);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 6, "カリン", 34002, 1, "2020/01/10 11:59:59", 0.0, 0.0, "ミッション報酬の受け取りは\nこちら！\n受け取り漏れの無いように\n気を付けてくださいね！", 1, -409.0, 0, "2020/01/04 5:00:00", 190801, 34);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "ペコリーヌ", 38001, 1, "2030/12/17 14:59:59", 0.0, 5.3, "過去のストーリーイベントを\n楽しめちゃいますよ！\n遊んだことのないものがあれば\n一緒にやってみましょう♪", 2, -458.0, 0, "2015/12/17 15:00:00", 105801, 38);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 2, "ペコリーヌ", 38002, 1, "2030/12/17 14:59:59", 0.0, 6.5, "これまでのイベントで登場した\n限定キャラを仲間にできたり\nメモリーピースが手に入る\nみたいですよ。やばいですね☆", 2, -458.0, 0, "2015/12/17 15:00:00", 105801, 38);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 0, "ペコリーヌ", 39005, 3, "2020/04/08 23:59:59", 9999.0, 0.0, "", 3, 9999.0, 0, "2020/04/01", 105801, 39);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 2, "カリン", 40001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "これまでに出題された\n問題を振り返ることが\nできますよ\n復習は大切です♪", 1, -430.0, 0, "2015/12/17 15:00:00", 190801, 40);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "シェフィ", 41001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ここでは腕試しが\nできるんですって。\n自分の実力を測るのに、\nちょうどよさそうね。", 1, -363.0, 2104010, "2015/12/17 15:00:00", 106401, 41);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "ペコリーヌ", 41002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ここで腕試しを\nしていきましょう！\n全力全開、\nがんばっちゃいますよ～！", 1, -363.0, 0, "2015/12/17 15:00:00", 105801, 41);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "キャル", 41003, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ここで腕試しが\nできるみたいね。\n試してみるのも\nいいんじゃない？", 1, -363.0, 0, "2015/12/17 15:00:00", 106001, 41);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "コッコロ", 41004, 1, "2030/12/17 14:59:59", 0.0, 0.0, "腕試しができるようです。\nここで練習を重ね、実戦に\n活かしてまいりましょう。", 1, -363.0, 0, "2015/12/17 15:00:00", 105901, 41);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "コッコロ", 42001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "訓練の成果に応じて、\n報酬がもらえるそうです。\n共に励んでいきましょう。", 1, -416.5, 0, "2015/12/17 15:00:00", 105901, 42);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "シェフィ", 42002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "目標を達成すれば、\n報酬がもらえるみたい。\n頑張り甲斐があるわね。", 1, -416.5, 2104010, "2015/12/17 15:00:00", 106401, 42);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "ペコリーヌ", 42003, 1, "2030/12/17 14:59:59", 0.0, 0.0, "腕試しをがんばれば、\n報酬がもらえますよ。\n挑戦していきましょう☆", 1, -416.5, 0, "2015/12/17 15:00:00", 105801, 42);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "キャル", 42004, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ミッションを達成すると、\n報酬が出るんですって。\n一緒にやってみましょ！", 1, -416.5, 0, "2015/12/17 15:00:00", 106001, 42);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "ペコリーヌ", 43001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ここからアリーナに\n挑戦できますよ！\n編成を工夫してライバルに\n挑んじゃいましょう！", 1, -363.0, 0, "2015/12/17 15:00:00", 105801, 43);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "コッコロ", 43002, 1, "2030/12/17 14:59:59", 0.0, 0.0, "こちらからアリーナに\n挑戦することができます。\n主さまらしい編成で\nライバルに挑みましょう。", 1, -363.0, 0, "2015/12/17 15:00:00", 105901, 43);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "キャル", 43003, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ここからアリーナに\n挑戦できるわよ！\nしっかり編成を考えて\nライバルに挑みなさい！", 1, -363.0, 0, "2015/12/17 15:00:00", 106001, 43);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "アメス", 43004, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ミッションをクリアすると報酬が\n受け取れるわ。ジャンジャン\nクリアしてバリバリ強化して\nあげなさい♪", 1, -416.5, 0, "2015/12/17 15:00:00", 123001, 44);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 2, "アメス", 43005, 1, "2030/12/17 14:59:59", 0.0, 0.0, "ぼんやりしてる場合じゃないわ。\n早くミッションをクリアして\n報酬を受け取ってきなさい！", 1, -416.5, 0, "2015/12/17 15:00:00", 123001, 44);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 3, "アメス", 43006, 1, "2030/12/17 14:59:59", 0.0, 5.79, "ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", 2, -416.5, 0, "2015/12/17 15:00:00", 123001, 45);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "アメス", 46001, 1, "2030/12/17 14:59:59", 0.0, 0.0, "はい、お疲れさま。\nここではマスタリーチケットを\n使って、マスタリー強化素材を\n手に入れることができるわよ。", 1, -371.5, 0, "2015/12/17 15:00:00", 123001, 46);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "シズル", 47001, 2, "2030/12/17 14:59:59", 0.0, 0.0, "呼ばれて飛び出てお姉ちゃんだよ♪\nたとえ火の中、水の中、迷宮の中っ\nこのダンジョンを踏破できるよう\n弟くんを応援してあげるからねっ♪", 2, -416.5, 0, "2015/12/17 15:00:00", 104901, 47);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 1, "リノ", 47002, 1, "2030/12/17 14:59:59", 0.0, 9.32, "ほんとーに不思議な場所ですね～\nお兄ちゃんが冒険を頑張れるよう\nおまじないをかけてあげますねっ\nフレーフレー、お・兄・ちゃんっ♪", 2, -416.5, 0, "2015/12/17 15:00:00", 101101, 47);
